import React from 'react';
import PropTypes from 'prop-types';
import classnames from 'classnames';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import FormControl from '@material-ui/core/FormControl';
import Radio from '@material-ui/core/Radio';
import RadioGroup from '@material-ui/core/RadioGroup';
import Checkbox from '@material-ui/core/Checkbox';
import FormHelperText from '@material-ui/core/FormHelperText';
import InputLabel from '@material-ui/core/InputLabel';
import Select from '@material-ui/core/Select';
import TextField from '@material-ui/core/TextField';

import moment from 'moment';
import MomentUtils from '@date-io/moment';
import { MuiPickersUtilsProvider, DateTimePicker } from 'material-ui-pickers';

import CKEditor from '@ckeditor/ckeditor5-react';
import ClassicEditor from '@ckeditor/ckeditor5-build-classic';

const renderFromHelper = ({ touched, error }) => {
    if (!(touched && error)) {
        return;
    } else {
        return <FormHelperText>{touched && error}</FormHelperText>;
    }
};

export const renderTextField = ({ label, input, type, meta: { touched, invalid, error }, ...custom }) => (
    <TextField label={label} type={type} placeholder={label} error={touched && invalid} helperText={touched && error} {...input} {...custom} />
);

// labelPlacement="start"
export const renderCheckbox = ({ input, label }) => (
    <FormControlLabel control={<Checkbox checked={input.value ? true : false} onChange={input.onChange} />} label={label} />
);

export const radioButton = ({ input, valueReceive, label, ...rest }) => {
    return (
        <RadioGroup {...input} {...rest} className="radioButton">
            <FormControlLabel value={valueReceive} control={<Radio />} label={label} />
        </RadioGroup>
    );
};

export const renderSelectField = ({ input, id, label, meta: { touched, error }, children, ...custom }) => {
    return (
        <FormControl error={touched && error}>
            <InputLabel htmlFor="age-native-simple">{label}</InputLabel>
            <Select
                native
                {...input}
                {...custom}
                inputProps={{
                    id: id,
                }}>
                {children}
            </Select>
            {renderFromHelper({ touched, error })}
        </FormControl>
    );
};

export const renderDatePicker = ({ input, label, defaultValue, disablePast, handleDateChange, meta: { touched, error } }) => {
    return (
        <FormControl error={touched && error}>
            <MuiPickersUtilsProvider utils={MomentUtils} moment={moment}>
                <DateTimePicker
                    {...input}
                    onChange={handleDateChange}
                    value={defaultValue || null}
                    format="DD/MM/YYYY hh:mm:ss"
                    disablePast={disablePast}
                    label={label}
                />
            </MuiPickersUtilsProvider>
            {renderFromHelper({ touched, error })}
        </FormControl>
    );
};

export const renderCkEditor = ({
    label,
    defaultValue,
    disabled,
    handleEditorOnInit,
    handleEditorChange,
    handleEditorBlur,
    handleEditorFocus,
    meta: { touched, error },
}) => {
    return (
        <FormControl error={touched && error}>
            <div className="lblForForm">{label}</div>
            <CKEditor
                editor={ClassicEditor}
                disabled={disabled}
                data={defaultValue ? defaultValue : null}
                onInit={editor => {
                    handleEditorOnInit(editor);
                }}
                onChange={(event, editor) => {
                    const data = editor.getData();
                    handleEditorChange({ event, editor, data });
                }}
                onBlur={editor => {
                    handleEditorBlur(editor);
                }}
                onFocus={editor => {
                    handleEditorFocus(editor);
                }}
            />
            {renderFromHelper({ touched, error })}
        </FormControl>
    );
};

export const renderImage = ({ label, defaultImg, disabled, handleImgUpload }) => {
    const classDisabled = classnames(disabled && 'disable');
    return (
        <FormControl>
            <div className="lblForForm">{label}</div>
            <div className={`wrapImgUpload ${classDisabled}`}>
                <input className="opacityHide inputFile" disabled={disabled} type="file" accept=".png, .jpg, .jpeg" onChange={handleImgUpload} />
                {defaultImg && <img src={defaultImg} alt="UploadImage" className="imgDefault" />}
                <span className="txt">Choose Image</span>
            </div>
        </FormControl>
    );
};

renderImage.propTypes = {
    label: PropTypes.string.isRequired,
    defaultImg: PropTypes.string,
    disabled: PropTypes.bool,
    handleImgUpload: PropTypes.func,
};

renderCkEditor.propTypes = {
    label: PropTypes.string.isRequired,
    meta: PropTypes.object,
    defaultValue: PropTypes.string,
    disabled: PropTypes.bool,
    handleEditorOnInit: PropTypes.func,
    handleEditorChange: PropTypes.func,
    handleEditorBlur: PropTypes.func,
    handleEditorFocus: PropTypes.func,
};

renderDatePicker.propTypes = {
    label: PropTypes.string.isRequired,
    input: PropTypes.object,
    meta: PropTypes.object,
    defaultValue: PropTypes.instanceOf(Date),
    disablePast: PropTypes.bool,
    handleDateChange: PropTypes.func,
};

renderTextField.propTypes = {
    label: PropTypes.string.isRequired,
    input: PropTypes.object,
    meta: PropTypes.object,
    type: PropTypes.string.isRequired,
};

renderFromHelper.propTypes = {
    touched: PropTypes.bool,
    error: PropTypes.string,
};

renderCheckbox.propTypes = {
    label: PropTypes.string.isRequired,
    input: PropTypes.object,
};

radioButton.propTypes = {
    input: PropTypes.object,
    label: PropTypes.string,
    valueReceive: PropTypes.string,
};

renderSelectField.propTypes = {
    id: PropTypes.string,
    label: PropTypes.string.isRequired,
    input: PropTypes.object,
    meta: PropTypes.object,
    children: PropTypes.array,
};
